class Solution:
    def new21Game(self, n: int, k: int, maxPts: int) -> float:
        dp = [0.0] * (n + 1)
        s = 0
        for i in range(k, n + 1):
            dp[i] = s / maxPts
            if i - maxPts - 1 >= 0:
                s = s - dp[i - maxPts - 1] + 1
            else:
                s += 1
        return sum(dp[k:])
